import{_ as d,X as r,Y as t,Z as e,$ as a,a1 as l,a0 as i,H as n}from"./framework-4f44829b.js";const c={},h=i('<h1 id="mysql" tabindex="-1"><a class="header-anchor" href="#mysql" aria-hidden="true">#</a> MySQL</h1><h2 id="记录结构" tabindex="-1"><a class="header-anchor" href="#记录结构" aria-hidden="true">#</a> 记录结构</h2><h2 id="索引" tabindex="-1"><a class="header-anchor" href="#索引" aria-hidden="true">#</a> 索引</h2>',3),s={href:"https://dunwu.github.io/db-tutorial/pages/9bb28f/#%E4%BD%95%E6%97%B6%E4%BD%BF%E7%94%A8%E7%B4%A2%E5%BC%95",target:"_blank",rel:"noopener noreferrer"},p=e("ul",null,[e("li",null,"B+树的索引数据在磁盘中的查找过程")],-1),u={href:"https://www.cnblogs.com/myseries/p/12532919.html",target:"_blank",rel:"noopener noreferrer"},b=i('<h2 id="连接" tabindex="-1"><a class="header-anchor" href="#连接" aria-hidden="true">#</a> 连接</h2><h2 id="查询优化" tabindex="-1"><a class="header-anchor" href="#查询优化" aria-hidden="true">#</a> 查询优化</h2><ul><li>explain字段含义</li></ul><h2 id="事务与锁" tabindex="-1"><a class="header-anchor" href="#事务与锁" aria-hidden="true">#</a> 事务与锁</h2><ul><li>数据库事务的特性</li></ul><blockquote><p><code>ACID</code>：</p><ul><li><p>Atomicity (原子性)</p><p>事务是一个不可分割的整体，事务内所有操作要么全做成功，要么全失败。</p></li><li><p>Consistency (一致性)</p><p>如果数据库中的数据全部符合现实世界中的约束（all defined rules），我们说这些数据就是一致的，或者说符合<code>一致性</code>的。</p></li><li><p>Isolation (隔离性)</p><p>多个并发事务之间相互隔离，不能互相干扰。</p></li><li><p>Durability (持久性)</p><p>对应的数据库操作所修改的数据都应该在磁盘上保留下来，不论之后发生了什么事故，本次转换造成的影响都不应该被丢失掉。</p></li></ul></blockquote><hr><h2 id="三大日志" tabindex="-1"><a class="header-anchor" href="#三大日志" aria-hidden="true">#</a> 三大日志</h2><h3 id="undo-log" tabindex="-1"><a class="header-anchor" href="#undo-log" aria-hidden="true">#</a> undo log</h3><h3 id="bin-log" tabindex="-1"><a class="header-anchor" href="#bin-log" aria-hidden="true">#</a> bin log</h3><h3 id="redo-log" tabindex="-1"><a class="header-anchor" href="#redo-log" aria-hidden="true">#</a> redo log</h3>',11),g={href:"https://juejin.cn/post/6844904117706440718",target:"_blank",rel:"noopener noreferrer"},f=i('<p>异步刷盘，buffer pool</p><hr><h2 id="分布式架构" tabindex="-1"><a class="header-anchor" href="#分布式架构" aria-hidden="true">#</a> 分布式架构</h2><ol><li>什么是主从同步，主从同步的作用</li></ol><blockquote><p>MySQL 的数据同步机制可以将数据从一个主数据库同步到另一个或多个从数据库，即 <code>Master-Slaves</code>模式。</p><ul><li><p>数据容灾、备份，数据冗余保证数据不丢失。</p></li><li><p>读写分离，可以动态地调整从服务器的数量，从而提高数据库的吞吐量与性能。</p></li><li><p>高可用，主从复制 + 故障切换，实现线上业务不宕机运行。</p></li></ul></blockquote><ol start="2"><li><p>主从同步是怎么进行的</p><figure><img src="https://raw.githubusercontent.com/nocetfy/image/main/img/image-20230209234111602.png" alt="主从同步" tabindex="0" loading="lazy"><figcaption>主从同步</figcaption></figure></li></ol><p>MySQL 存在三种<strong>线程</strong>模型，用于主从之间的数据同步：</p><blockquote><ol><li><code>Binlog dump thread</code></li></ol><p>当从库与主库建立一个连接时，主库中会创建出一个线程（<code>Binlog dump thread</code>），该线程用于当 <code>binlog</code>日志的内容发生变化时，该线程会通知从库，并将相应的 <code>binlog</code>内容发送给从库。</p><ol start="2"><li><code>Slave I/O thread</code></li></ol><p>当主从同步开启的时候，从库上会创建<strong>2个线程</strong>。第一个就是 <code>I/O</code>线程（<code>Slave I/O thread</code>），该线程连接到主库，主库上的 <code>binlog dump线程</code>会将 <code>binlog</code>的内容发送给该 <code>I/O线程</code>。该 <code>I/O</code>线程接收到 <code>binlog</code>内容后，再将变更的内容写入到本地的 <code>relay log</code>。</p><ol start="3"><li><code>Slave SQL thread</code></li></ol><p>当 <code>I/O</code>线程将变更的内容写入到本地的 <code>relay log</code>后，<code>SQL</code>线程（<code>Slave SQL thread</code>）会对 <code>relay log</code>进行读取，并且根据 <code>relay log</code>的内容对从库做相应的操作。</p></blockquote><p>需要注意的是，当一个主库有多个从库时，在主库上会为每个从库都创建一个 <code>Binlog dump thread</code>，而每个从库都会创建属于自己的 <code>I/O thread</code>与 <code>SQL thread</code>。</p><blockquote><p>基于TCP包进行同步</p></blockquote><hr><h2 id="sql优化" tabindex="-1"><a class="header-anchor" href="#sql优化" aria-hidden="true">#</a> SQL优化</h2><h3 id="慢sql的危害" tabindex="-1"><a class="header-anchor" href="#慢sql的危害" aria-hidden="true">#</a> 慢SQL的危害</h3><blockquote><p>不在数据库锁，因为是MVCC快照读， 而在长期吃数据库连接资源，拖了qps。</p></blockquote><h3 id="优化方法" tabindex="-1"><a class="header-anchor" href="#优化方法" aria-hidden="true">#</a> 优化方法</h3><ol><li>MySQL有两种排序方式filesort和index，一个通过文件排序，一个通过扫描索引本身完成排序。</li><li>尽量使用覆盖索引，查询中少使用像”SELECT * &quot;，尽量将查询字段和索引字段相匹配。</li><li>如果ORDER BY 的条件不在索引列上，就会产生 filesort，效率降低，详见实例5</li><li>ORDER BY满足两种情况会使用Index Sort <ul><li>ORDER BY语句满足最左前缀原则。</li><li>WHERE条件与ORDER BY满足最左前缀原则。</li></ul></li><li>group by与order by很类似，其实质是先排序后分组，遵照索引创建顺序的最左前缀法则。对于group by的优化如果不需要排序的可以加上order by null禁止排序。注意，where高于having，能写在where中的限定条件就不要去having限定了。</li><li>关联字段加索引，让MySQL做join操作时候尽量选择NLJ算法。</li><li>小表驱动大表，写多表连接SQL时，如果明知道哪张表是小表可以用straight_join写法固定连接驱动方式，省去MySQL优化区判断的时间。</li></ol>',16);function _(m,y){const o=n("ExternalLinkIcon");return r(),t("div",null,[h,e("p",null,[e("a",s,[a("https://dunwu.github.io/db-tutorial/pages/9bb28f/#何时使用索引"),l(o)])]),p,e("p",null,[e("a",u,[a("https://www.cnblogs.com/myseries/p/12532919.html"),l(o)])]),b,e("p",null,[e("a",g,[a("https://juejin.cn/post/6844904117706440718"),l(o)])]),f])}const S=d(c,[["render",_],["__file","MySQL.html.vue"]]);export{S as default};
